import { notify } from '../helpers/notification.helpers';

export const useNotification = (): [React.Dispatch<React.SetStateAction<HTMLElement | null>>, (props: Parameters<typeof notify>[1]) => Promise<void>] => {
  const notificationElem = useContext(NotificationContext);
  const dispatch = (elem: HTMLElement | null) => {
    notificationElem.current = elem;
  };

  const notifyHandler = async (props: Parameters<typeof notify>[1]) => {
    if (!notificationElem.current) return;

    try {
